class Solution {
    public boolean canMeasureWater(int x, int y, int target) {
        if (target > x + y) return false;
        if (x == 0 || y == 0) return target == 0 || target == x + y;
        int gcd = gcd(x, y);
        return target % gcd == 0;
    }

    private int gcd(int a, int b) {
        if (b == 0) return a;
        return gcd(b, a % b);
    }
}
